const current = $items('Turn Counter').at(-1).json;
const query = String(current.query || current.messages?.find(m => m.role === 'user')?.content || '').toLowerCase();
const message = $json.choices?.[0]?.message || {};
const toolCalls = Array.isArray(message.tool_calls) ? message.tool_calls : [];

const cityNames = ['islamabad', 'lahore', 'karachi'];
const title = (text, fallback = '') => text ? text.charAt(0).toUpperCase() + text.slice(1) : fallback;
const mentionedCity = cityNames.find(city => query.includes(city)) || 'lahore';
const fromMatch = query.match(/from\s+(islamabad|lahore|karachi)\s+to\s+(islamabad|lahore|karachi)/i);
const toCurrency = query.includes('gbp') ? 'GBP' : query.includes('usd') ? 'USD' : query.includes('aed') ? 'AED' : '';
const university = query.includes('punjab') ? 'Punjab University' : query.includes('nust') ? 'NUST' : 'University area';

const plan = {
  weather: /weather|temperature|forecast/.test(query),
  currency: /currency|convert|gbp|usd|aed|foreign/.test(query),
  room: /hostel|room|rent|university|campus|accommodation/.test(query),
  transport: /transport|travel|bus|train|from\s+.+\s+to/.test(query),
  city: title(mentionedCity, 'Lahore'),
  university,
  from_city: fromMatch ? title(fromMatch[1]) : 'Islamabad',
  to_city: fromMatch ? title(fromMatch[2]) : title(mentionedCity, 'Lahore'),
  to_currency: toCurrency || 'PKR'
};

for (const call of toolCalls) {
  const name = call.function?.name;
  let args = {};
  try { args = JSON.parse(call.function?.arguments || '{}'); } catch (error) { args = {}; }
  if (name === 'get_weather') { plan.weather = true; plan.city = args.city || plan.city; }
  if (name === 'get_room_cost') { plan.room = true; plan.city = args.city || plan.city; plan.university = args.university || plan.university; }
  if (name === 'get_transport_cost') { plan.transport = true; plan.from_city = args.from_city || plan.from_city; plan.to_city = args.to_city || plan.to_city; }
  if (name === 'convert_currency') { plan.currency = true; plan.to_currency = args.to_currency || plan.to_currency; }
}

if (!plan.room && !plan.transport && !plan.weather && !plan.currency) {
  plan.room = true;
}

return [{ json: { ...current, plan, results: {}, tool_calls: [], llm_rate_limited: Boolean($json.error) } }];

const plan = $json.plan || {};
const results = $json.results || {};
const calls = $json.tool_calls || [];
if (plan.weather) {
  const weather = {
    islamabad: { temperature: '28 deg C', condition: 'Partly Cloudy', humidity: '55%' },
    karachi: { temperature: '34 deg C', condition: 'Hot and Sunny', humidity: '70%' },
    lahore: { temperature: '32 deg C', condition: 'Hazy', humidity: '60%' }
  };
  const city = String(plan.city || 'Lahore').toLowerCase();
  results.weather = { city: plan.city || 'Lahore', ...(weather[city] || weather.lahore) };
  calls.push({ tool_name: 'get_weather', arguments: { city: plan.city || 'Lahore' }, result: results.weather });
}
return [{ json: { ...$json, results, tool_calls: calls } }];

const plan = $json.plan || {};
const results = $json.results || {};
const calls = $json.tool_calls || [];
if (plan.currency) {
  const rates = { PKR: 1, USD: 278.5, GBP: 352, AED: 75.8 };
  const to = String(plan.to_currency || 'PKR').toUpperCase();
  const amount = Number(results.room?.monthly_room_cost_pkr || 24000) + Number(results.transport?.estimated_cost_pkr || 0);
  const converted = amount / (rates[to] || 1);
  results.currency = { original: `${amount.toLocaleString()} PKR`, converted: `${converted.toFixed(2)} ${to}` };
  calls.push({ tool_name: 'convert_currency', arguments: { amount, from_currency: 'PKR', to_currency: to }, result: results.currency });
}
return [{ json: { ...$json, results, tool_calls: calls } }];

const plan = $json.plan || {};
const results = $json.results || {};
const calls = $json.tool_calls || [];
if (plan.room) {
  const city = String(plan.city || 'Lahore').toLowerCase();
  const base = city === 'islamabad' ? 32000 : city === 'karachi' ? 26000 : 24000;
  results.room = { city: plan.city || 'Lahore', university: plan.university || 'University area', monthly_room_cost: `PKR ${base.toLocaleString()}`, monthly_room_cost_pkr: base, note: 'Shared hostel room estimate near campus.' };
  calls.push({ tool_name: 'get_room_cost', arguments: { city: plan.city || 'Lahore', university: plan.university || 'University area' }, result: results.room });
}
return [{ json: { ...$json, results, tool_calls: calls } }];

const plan = $json.plan || {};
const results = $json.results || {};
const calls = $json.tool_calls || [];
if (plan.transport) {
  const routes = { 'lahore-karachi': 7500, 'islamabad-lahore': 3200, 'islamabad-karachi': 9000 };
  const fromCity = String(plan.from_city || 'Islamabad').toLowerCase();
  const toCity = String(plan.to_city || plan.city || 'Lahore').toLowerCase();
  const key = `${fromCity}-${toCity}`;
  const reverse = `${toCity}-${fromCity}`;
  const cost = routes[key] || routes[reverse] || 5000;
  results.transport = { route: `${plan.from_city || 'Islamabad'} to ${plan.to_city || plan.city || 'Lahore'}`, estimated_cost: `PKR ${cost.toLocaleString()}`, estimated_cost_pkr: cost, mode: 'Bus or economy train estimate' };
  calls.push({ tool_name: 'get_transport_cost', arguments: { from_city: plan.from_city || 'Islamabad', to_city: plan.to_city || plan.city || 'Lahore' }, result: results.transport });
}
return [{ json: { ...$json, results, tool_calls: calls } }];

const results = $json.results || {};
const parts = [];
if (results.room) parts.push(`Room near ${results.room.university} in ${results.room.city}: ${results.room.monthly_room_cost} per month (${results.room.note})`);
if (results.transport) parts.push(`Transport ${results.transport.route}: ${results.transport.estimated_cost} by ${results.transport.mode}.`);
if (results.weather) parts.push(`Weather in ${results.weather.city}: ${results.weather.temperature}, ${results.weather.condition}, humidity ${results.weather.humidity}.`);
if (results.currency) parts.push(`Converted estimated cost: ${results.currency.converted} (${results.currency.original}).`);
const note = $json.llm_rate_limited ? ' Groq was rate-limited, so the workflow used the deterministic local tool router.' : '';
return [{ json: { ...$json, final_answer: `${parts.join(' ')}${note}`.trim() || 'No matching tool was required.', tool_call_count: ($json.tool_calls || []).length } }];
